// Captura a string base64 que vem da Evolution API
const base64String = $input.item.json.base64;

// O n8n precisa que o conteúdo binário seja um Buffer para ser processado corretamente
const buffer = Buffer.from(base64String, 'base64');

return {
  json: $input.item.json, // Mantém os dados JSON originais se precisar deles
  binary: {
    data: {
      data: buffer.toString('base64'), // O n8n converterá isso internamente
      mimeType: 'image/jpeg',
      fileName: 'whatsapp_image.jpg',
    }
  }
};

// 1. Captura a string base64
let base64String = $input.item.json.base64;

// 2. Limpeza de segurança: Se a string vier com o prefixo "data:audio/...", nós o removemos
if (base64String.includes(',')) {
  base64String = base64String.split(',')[1];
}

return {
  json: $input.item.json,
  binary: {
    data: { // Este nome 'data' deve ser o mesmo que você colocou no campo "Input Data Field" do nó OpenAI
      data: base64String,
      mimeType: 'audio/ogg', 
      fileName: 'audio.ogg', // A extensão .ogg é vital para o Whisper
    }
  }
};

